import{c as l,Q as i,j as t,m as s}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"上架审核、隐私材料与合规清单","description":"","frontmatter":{},"headers":[],"relativePath":"mobileCommonLearning/11-上架审核隐私材料与合规清单.md","filePath":"mobileCommonLearning/11-上架审核隐私材料与合规清单.md","lastUpdated":1780912084000}'),e={name:"mobileCommonLearning/11-上架审核隐私材料与合规清单.md"};function n(p,a,o,d,h,r){return i(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="上架审核、隐私材料与合规清单" tabindex="-1">上架审核、隐私材料与合规清单 <a class="header-anchor" href="#上架审核、隐私材料与合规清单" aria-label="Permalink to &quot;上架审核、隐私材料与合规清单&quot;">​</a></h1><p>商店审核不是最后补材料。很多审核问题来自项目一开始就没记录权限、数据和第三方 SDK。</p><p>一句话先记住:<strong>移动端合规 = 你收集什么、为什么收集、传给谁、用户怎么知道和控制。</strong></p><hr><h2 id="一、审核看什么" tabindex="-1">一、审核看什么 <a class="header-anchor" href="#一、审核看什么" aria-label="Permalink to &quot;一、审核看什么&quot;">​</a></h2><p>常见关注点:</p><ul><li>App 功能是否真实可用</li><li>权限用途是否合理</li><li>隐私政策是否完整</li><li>数据收集声明是否一致</li><li>登录和账号删除是否符合要求</li><li>内购 / 支付是否合规</li><li>诱导、欺诈、虚假功能</li><li>崩溃和明显 bug</li><li>截图、名称、描述是否误导</li></ul><p>审核不是只看包能不能安装。</p><hr><h2 id="二、隐私政策" tabindex="-1">二、隐私政策 <a class="header-anchor" href="#二、隐私政策" aria-label="Permalink to &quot;二、隐私政策&quot;">​</a></h2><p>隐私政策至少说明:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>收集哪些信息</span></span>
<span class="line"><span>用途是什么</span></span>
<span class="line"><span>是否共享给第三方</span></span>
<span class="line"><span>保存多久</span></span>
<span class="line"><span>用户如何删除账号和数据</span></span>
<span class="line"><span>如何联系开发者</span></span></code></pre></div><p>不要复制一份模板就不管。实际 SDK 收集的数据要和隐私政策一致。</p><hr><h2 id="三、权限用途说明" tabindex="-1">三、权限用途说明 <a class="header-anchor" href="#三、权限用途说明" aria-label="Permalink to &quot;三、权限用途说明&quot;">​</a></h2><p>权限文案要具体。</p><p>差:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>需要访问相机</span></span></code></pre></div><p>好:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用于拍摄头像和上传工单图片</span></span></code></pre></div><p>权限申请时机:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户触发功能时申请</span></span>
<span class="line"><span>不要 App 启动就申请一堆权限</span></span></code></pre></div><p>提前申请会降低通过率和用户信任。</p><hr><h2 id="四、ios-privacy-manifest" tabindex="-1">四、iOS Privacy Manifest <a class="header-anchor" href="#四、ios-privacy-manifest" aria-label="Permalink to &quot;四、iOS Privacy Manifest&quot;">​</a></h2><p>iOS 生态越来越强调隐私声明。涉及隐私 API、第三方 SDK、数据收集时,要按 Apple 要求补充材料。</p><p>工程上要做:</p><ul><li>盘点使用的 SDK</li><li>记录 SDK 收集的数据类型</li><li>记录是否追踪用户</li><li>检查是否需要 Privacy Manifest</li><li>上架前和 App Store Connect 隐私问卷对齐</li></ul><p>具体字段会随 Apple 政策变化,每次发版前查官方文档。</p><hr><h2 id="五、google-play-data-safety" tabindex="-1">五、Google Play Data safety <a class="header-anchor" href="#五、google-play-data-safety" aria-label="Permalink to &quot;五、Google Play Data safety&quot;">​</a></h2><p>Google Play 要填写 Data safety。</p><p>你要回答:</p><ul><li>收集哪些数据</li><li>是否共享</li><li>是否加密传输</li><li>用户是否可请求删除</li><li>数据是否可选</li><li>用于哪些目的</li></ul><p>填写必须和实际 SDK 行为一致。广告、统计、崩溃 SDK 都要算。</p><hr><h2 id="六、国内市场材料" tabindex="-1">六、国内市场材料 <a class="header-anchor" href="#六、国内市场材料" aria-label="Permalink to &quot;六、国内市场材料&quot;">​</a></h2><p>常见材料:</p><ul><li>软件著作权</li><li>营业执照</li><li>ICP 备案 / 网站信息</li><li>隐私政策 URL</li><li>用户协议 URL</li><li>权限说明</li><li>安全评估或 SDK 合规说明</li><li>应用截图</li><li>测试账号</li></ul><p>不同渠道要求不同,要有材料台账。</p><hr><h2 id="七、账号删除" tabindex="-1">七、账号删除 <a class="header-anchor" href="#七、账号删除" aria-label="Permalink to &quot;七、账号删除&quot;">​</a></h2><p>很多场景都需要提供账号删除能力:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App 内入口</span></span>
<span class="line"><span>网页入口</span></span>
<span class="line"><span>客服流程</span></span></code></pre></div><p>删除要说明:</p><ul><li>删除什么数据</li><li>保留什么数据</li><li>多久生效</li><li>是否可恢复</li></ul><p>不要只写&quot;联系客服&quot;但没有实际流程。</p><hr><h2 id="八、第三方-sdk-清单" tabindex="-1">八、第三方 SDK 清单 <a class="header-anchor" href="#八、第三方-sdk-清单" aria-label="Permalink to &quot;八、第三方 SDK 清单&quot;">​</a></h2><p>维护一张表:</p><table tabindex="0"><thead><tr><th>SDK</th><th>用途</th><th>收集数据</th><th>是否出境</th><th>隐私文档</th></tr></thead><tbody><tr><td>Crash SDK</td><td>崩溃分析</td><td>设备、崩溃日志</td><td>视服务而定</td><td>URL</td></tr><tr><td>Analytics</td><td>行为分析</td><td>事件、设备标识</td><td>视服务而定</td><td>URL</td></tr><tr><td>Push SDK</td><td>推送</td><td>token、设备信息</td><td>视服务而定</td><td>URL</td></tr></tbody></table><p>SDK 升级时要重新检查隐私行为。</p><hr><h2 id="九、什么时候会出事故" tabindex="-1">九、什么时候会出事故 <a class="header-anchor" href="#九、什么时候会出事故" aria-label="Permalink to &quot;九、什么时候会出事故&quot;">​</a></h2><ol><li>使用相机权限,隐私政策没写。</li><li>SDK 收集设备标识,Data safety 没声明。</li><li>iOS 审核员没有测试账号,无法进入核心页面。</li><li>国内市场要求软著,临发版才发现没有。</li><li>权限在启动时弹出,审核认为用途不明确。</li><li>没有账号删除入口,被拒审。</li></ol><hr><h2 id="十、检查清单" tabindex="-1">十、检查清单 <a class="header-anchor" href="#十、检查清单" aria-label="Permalink to &quot;十、检查清单&quot;">​</a></h2><ul><li>[ ] 隐私政策 URL 是否可访问</li><li>[ ] 用户协议 URL 是否可访问</li><li>[ ] 权限用途是否逐项说明</li><li>[ ] iOS 隐私问卷是否和实际一致</li><li>[ ] Google Play Data safety 是否和实际一致</li><li>[ ] 第三方 SDK 清单是否维护</li><li>[ ] 是否有账号删除流程</li><li>[ ] 国内渠道材料是否齐全</li><li>[ ] 是否提供审核测试账号</li><li>[ ] 上架截图和描述是否与功能一致</li></ul><hr><h2 id="十一、心智模型" tabindex="-1">十一、心智模型 <a class="header-anchor" href="#十一、心智模型" aria-label="Permalink to &quot;十一、心智模型&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>权限说明给用户看</span></span>
<span class="line"><span>隐私政策给用户和审核看</span></span>
<span class="line"><span>Data safety / 隐私问卷给商店看</span></span>
<span class="line"><span>SDK 清单给团队长期维护</span></span>
<span class="line"><span>测试账号给审核员进应用</span></span></code></pre></div><p>下一篇 12 讲权限模型。</p>`,62)])])}const b=l(e,[["render",n]]);export{u as __pageData,b as default};
